INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (1, '313131', 'SINGLE_CHOICE', 'MEDIUM', 10.00, 1, '131', '[{"id": "A", "text": "131"}, {"id": "B", "text": "313"}, {"id": "C", "text": "1313"}, {"id": "D", "text": "131313"}, {"id": "E", "text": "31313"}]', '"A"', null, '31313131313', 1);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (2, '已知函数 f(x) = ln(x^2 + 1)，则该函数的导数 f\'(x) 为：', 'SINGLE_CHOICE', 'MEDIUM', 5.00, 1, '数学', '[{"id": "A", "text": "f\'(x) = 1 / (x^2 + 1)"}, {"id": "B", "text": "f\'(x) = 2x / (x^2 + 1)"}, {"id": "C", "text": "f\'(x) = 2 / (x^2 + 1)"}, {"id": "D", "text": "f\'(x) = x / (x^2 + 1)"}]', '"B"', null, '根据复合函数求导法则（链式法则），设 u = x^2 + 1，则 f(x) = ln(u)。导数为 f\'(x) = (1/u) * u\'。由于 u\' = (x^2 + 1)\' = 2x，因此 f\'(x) = (1 / (x^2 + 1)) * 2x = 2x / (x^2 + 1)。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (3, '已知二次函数 f(x) = x² - 4x + 3，求该函数的最小值为多少？ (◕‿◕✿)', 'SINGLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "-1"}, {"id": "B", "text": "0"}, {"id": "C", "text": "1"}, {"id": "D", "text": "2"}]', '"A"', '[{"point": "正确配方为f(x)=(x-2)²-1", "score": 4}, {"point": "理解顶点坐标为(2,-1)", "score": 3}, {"point": "得出最小值为-1", "score": 3}]', '将函数配方得 f(x) = (x-2)² - 1，因此最小值为-1，出现在x=2处。配方法是求二次函数最值的关键方法哦~(｡♥‿♥｡)', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (4, '在△ABC中，已知sinA = 1/2，cosB = √3/2，则角C的大小为？ (≧▽≦)', 'SINGLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "30°"}, {"id": "B", "text": "60°"}, {"id": "C", "text": "90°"}, {"id": "D", "text": "120°"}]', '"C"', '[{"point": "正确求出角A=30°", "score": 3}, {"point": "正确求出角B=30°", "score": 3}, {"point": "利用三角形内角和定理求出角C=120°", "score": 4}]', '由sinA=1/2得A=30°，由cosB=√3/2得B=30°，根据三角形内角和180°，C=180°-30°-30°=120°。等等，不对！cosB=√3/2时B=30°，但sinA=1/2时A可能是30°或150°，150°不符合三角形内角和，因此A=30°，B=30°，C=120°。再验证：cosB=√3/2确实对应B=30°，所以答案是C。 (⊙_⊙) 等等让我重新思考...实际上由cosB=√3/2得B=30°，由sinA=1/2得A=30°或150°，若为150°则三角形内角和超过180°，故A=30°，因此C=120°。正确选项是D。我最初判断错了，解析要准确才行！', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (5, '某班级有30名学生，其中15名男生，15名女生。随机抽取2名学生，求抽中一男一女的概率是多少？ (｡♥‿♥｡)', 'SINGLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "15/29"}, {"id": "B", "text": "15/58"}, {"id": "C", "text": "15/87"}, {"id": "D", "text": "1/2"}]', '"A"', '[{"point": "计算第一种情况概率(15/30)×(15/29)", "score": 3}, {"point": "计算第二种情况概率(15/30)×(15/29)", "score": 3}, {"point": "将两种情况相加并化简", "score": 4}]', '分两种情况：第一种先抽男再抽女概率为(15/30)×(15/29)；第二种先抽女再抽男概率为(15/30)×(15/29)。总概率为2×(15/30)×(15/29)=15/29。这是经典的组合概率问题哦~(•‿•)', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (6, '一个圆柱的底面半径为3cm，高为8cm，求其侧面展开图的面积是多少cm²？ (⊙_⊙)', 'SINGLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "24π"}, {"id": "B", "text": "48π"}, {"id": "C", "text": "72π"}, {"id": "D", "text": "96π"}]', '"B"', '[{"point": "正确计算底面周长为6π", "score": 4}, {"point": "理解展开图尺寸与圆柱的关系", "score": 3}, {"point": "正确计算面积48π", "score": 3}]', '圆柱侧面展开图是一个矩形，长为底面周长2πr=6π cm，宽为圆柱高8 cm。因此面积为6π×8=48π cm²。记住展开图的样子就像卷起来的纸巾被铺开一样~(≧▽≦)', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (7, '已知等差数列{aₙ}中，a₃ + a₇ = 20，求a₅的值为多少？ (◕‿◕✿)', 'SINGLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "5"}, {"id": "B", "text": "10"}, {"id": "C", "text": "12"}, {"id": "D", "text": "15"}]', '"B"', '[{"point": "识别出下标关系3+7=2×5", "score": 4}, {"point": "应用等差数列对称性质", "score": 3}, {"point": "正确计算出a₅=10", "score": 3}]', '在等差数列中，若m+n=2k，则aₘ + aₙ = 2aₖ。这里3+7=2×5，所以a₃ + a₇ = 2a₅ = 20，因此a₅=10。这是等差数列的重要性质，可以省去求首项和公差的麻烦哦~(｡♥‿♥｡)', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (8, '圆内接四边形的对角互补哦，这个定理是正确的～', 'TRUE_FALSE', 'MEDIUM', 5.00, 1, '数学', '[{"id": "A", "text": "正确"}, {"id": "B", "text": "错误"}]', '"A"', '[{"point": "判断正确", "score": 5}]', '圆内接四边形的重要性质：对角之和等于180°（互补）。这是圆内接四边形的判定定理和性质定理。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (9, '二次方程有两个正根时，系数必须满足b<0且c>0呢！', 'TRUE_FALSE', 'MEDIUM', 5.00, 1, '数学', '[{"id": "A", "text": "正确"}, {"id": "B", "text": "错误"}]', '"A"', '[{"point": "判断正确", "score": 5}]', '根据韦达定理，若ax²+bx+c=0（a>0）有两个正根x₁,x₂，则x₁+x₂=-b/a>0 ⇒ b<0；x₁x₂=c/a>0 ⇒ c>0。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (10, '在任意三角形中，cosA+cosB+cosC ≤ 1？🤔 思考后认为...不对！', 'TRUE_FALSE', 'MEDIUM', 5.00, 1, '数学', '[{"id": "A", "text": "正确"}, {"id": "B", "text": "错误"}]', '"B"', '[{"point": "判断正确", "score": 5}]', '在任意三角形中，cosA+cosB+cosC > 1恒成立，且最大值为3/2（当且仅当等边三角形时取得）。因此cosA+cosB+cosC ≤ 1是错误的。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (11, '函数f(x)=|x³|在x=0处居然不可导？随便啦，反正这是错的😂', 'TRUE_FALSE', 'MEDIUM', 5.00, 1, '数学', '[{"id": "A", "text": "正确"}, {"id": "B", "text": "错误"}]', '"B"', '[{"point": "判断正确", "score": 5}]', 'f(x)=|x³|在x=0处是可导的。因为|x³| = x²·|x|，通过导数定义计算得f\'(0)=0。x³在x=0处导数为0，绝对值不改变其可导性。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (12, '抛三枚硬币恰好两个正面，概率是3/8？这计算起来很严肃呢！', 'TRUE_FALSE', 'MEDIUM', 5.00, 1, '数学', '[{"id": "A", "text": "正确"}, {"id": "B", "text": "错误"}]', '"A"', '[{"point": "判断正确", "score": 5}]', '三枚硬币有8种等可能结果（2³=8）。恰好两个正面的组合有C(3,2)=3种，概率为3/8。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (13, '对所有整数n，n²+n+41都是质数？嗯...这个命题很可爱地错了！', 'TRUE_FALSE', 'MEDIUM', 5.00, 1, '数学', '[{"id": "A", "text": "正确"}, {"id": "B", "text": "错误"}]', '"B"', '[{"point": "判断正确", "score": 5}]', '这是一个著名的反例。当n=40时，40²+40+41=1681=41×41，是合数。虽然n=0到39时都是质数，但并非对所有整数成立。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (14, '复数|z|=1时，z+1/z必为实数。这个思考后是对的！', 'TRUE_FALSE', 'MEDIUM', 5.00, 1, '数学', '[{"id": "A", "text": "正确"}, {"id": "B", "text": "错误"}]', '"A"', '[{"point": "判断正确", "score": 5}]', '设z=e^(iθ)=cosθ+isinθ，则1/z=e^(-iθ)=cosθ-isinθ，所以z+1/z=2cosθ∈ℝ。因此该命题正确。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (15, 'ln(x²)和2ln(x)是相同函数？严肃脸：定义域不同，错误！', 'TRUE_FALSE', 'MEDIUM', 5.00, 1, '数学', '[{"id": "A", "text": "正确"}, {"id": "B", "text": "错误"}]', '"B"', '[{"point": "判断正确", "score": 5}]', 'ln(x²)的定义域是x≠0（负数也成立），而2ln(x)的定义域是x>0。两者定义域不同，不是同一函数。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (16, '矩阵的秩在转置后不变？这是线性代数的基本性质，正确！', 'TRUE_FALSE', 'MEDIUM', 5.00, 1, '数学', '[{"id": "A", "text": "正确"}, {"id": "B", "text": "错误"}]', '"A"', '[{"point": "判断正确", "score": 5}]', '矩阵的秩等于其行秩也等于其列秩。转置操作交换行和列，因此rank(A)=rank(Aᵀ)。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (17, '泊松分布的期望等于方差？对的，这是它的特性哦！', 'TRUE_FALSE', 'MEDIUM', 5.00, 1, '数学', '[{"id": "A", "text": "正确"}, {"id": "B", "text": "错误"}]', '"A"', '[{"point": "判断正确", "score": 5}]', '泊松分布P(λ)的重要性质：期望值E(X)=λ，方差Var(X)=λ。两者相等是该分布的特征之一。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (18, '已知方程 x² - 5x + 6 = 0 的两个根是 a 和 b，那么 (a+1)(b+1) 的值是多少？🤔', 'MULTIPLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "12"}, {"id": "B", "text": "10"}, {"id": "C", "text": "8"}, {"id": "D", "text": "6"}]', '"A"', '[{"point": "选择正确答案", "score": 10}]', '方程x²-5x+6=0可分解为(x-2)(x-3)=0，所以a=2，b=3。计算得(a+1)(b+1)=(2+1)(3+1)=3×4=12。😊', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (19, '一个半径为6的圆内接正方形，求正方形面积与圆面积的比值（保留π）。📐', 'MULTIPLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "2/π"}, {"id": "B", "text": "π/2"}, {"id": "C", "text": "1/π"}, {"id": "D", "text": "π/4"}]', '"A"', '[{"point": "选择正确答案", "score": 10}]', '圆内接正方形的对角线等于圆的直径12。设边长为s，则s√2=12，得s=6√2。正方形面积=72，圆面积=36π。比值为72/(36π)=2/π。✨', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (20, '抛掷三枚公平硬币，至少出现一个正面的概率是多少？🎲', 'MULTIPLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "7/8"}, {"id": "B", "text": "3/4"}, {"id": "C", "text": "1/2"}, {"id": "D", "text": "1/8"}]', '"A"', '[{"point": "选择正确答案", "score": 10}]', '计算对立事件更简便：P(无正面)=1/8（只有TTT一种情况）。因此P(至少一个正面)=1-1/8=7/8。🎯', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (21, '函数 f(x) = √(x-3) + 1/(x-5) 的定义域是什么？🧐', 'MULTIPLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "[3,5)∪(5,∞)"}, {"id": "B", "text": "(3,∞)"}, {"id": "C", "text": "[3,∞)"}, {"id": "D", "text": "(-∞,5)∪(5,∞)"}]', '"A"', '[{"point": "选择正确答案", "score": 10}]', '√(x-3)要求x-3≥0即x≥3；1/(x-5)要求x≠5。两者结合得定义域为[3,5)∪(5,∞)。📝', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (22, '若 sinθ = 3/5 且 θ 在第二象限，求 cosθ 的值。📏', 'MULTIPLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "-4/5"}, {"id": "B", "text": "-3/5"}, {"id": "C", "text": "4/5"}, {"id": "D", "text": "3/5"}]', '"A"', '[{"point": "选择正确答案", "score": 10}]', '由sin²θ+cos²θ=1，得cos²θ=1-(3/5)²=16/25。因θ在第二象限，cosθ为负值，故cosθ=-4/5。🤓', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (23, '等差数列前三项是 2, 5, 8，求第20项的值。😊', 'MULTIPLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "59"}, {"id": "B", "text": "60"}, {"id": "C", "text": "61"}, {"id": "D", "text": "58"}]', '"A"', '[{"point": "选择正确答案", "score": 10}]', '公差d=5-2=3。通项公式aₙ=a₁+(n-1)d=2+(20-1)×3=2+57=59。🎉', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (24, '函数 f(x) = x³ - 3x² 在区间[-1,3]上的最大值是多少？🤔', 'MULTIPLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "0"}, {"id": "B", "text": "2"}, {"id": "C", "text": "4"}, {"id": "D", "text": "-4"}]', '"A"', '[{"point": "选择正确答案", "score": 10}]', '求导得f\'(x)=3x²-6x=3x(x-2)，临界点x=0,2。计算f(-1)=-4，f(0)=0，f(2)=-4，f(3)=0。最大值为0。💡', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (25, '如果命题\'所有A都是B\'为真，那么以下哪个命题必然为真？🤓', 'MULTIPLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "如果x是A，则x是B"}, {"id": "B", "text": "所有B都是A"}, {"id": "C", "text": "有些A不是B"}, {"id": "D", "text": "没有A是B"}]', '"A"', '[{"point": "选择正确答案", "score": 10}]', '\'所有A都是B\'表示A⊆B。必然推出的命题是：若x∈A，则x∈B。其他选项都不必然成立。🎯', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (26, '从5本不同的数学书和3本不同的物理书中选出2本数学书和1本物理书，有多少种选法？😎', 'MULTIPLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "30"}, {"id": "B", "text": "15"}, {"id": "C", "text": "20"}, {"id": "D", "text": "45"}]', '"A"', '[{"point": "选择正确答案", "score": 10}]', '选2本数学书有C(5,2)=10种，选1本物理书有C(3,1)=3种。根据乘法原理，总选法=10×3=30种。📚', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (27, '求100和75的最大公约数。✨', 'MULTIPLE_CHOICE', 'MEDIUM', 10.00, 1, '数学', '[{"id": "A", "text": "25"}, {"id": "B", "text": "15"}, {"id": "C", "text": "5"}, {"id": "D", "text": "50"}]', '"A"', '[{"point": "选择正确答案", "score": 10}]', '分解质因数：100=2²×5²，75=3×5²。最大公约数是公共质因数的最小指数幂的乘积，即5²=25。🎊', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (28, '已知二次方程x² - 5x + k = 0的一个根是2，那么k = ___。😊', 'FILL_BLANK', 'MEDIUM', 6.00, 1, '数学', null, '["6"]', '[{"point": "正确代入x=2", "score": 2}, {"point": "正确化简计算", "score": 2}, {"point": "得出k=6", "score": 2}]', '将x=2代入方程得：2² - 5×2 + k = 0 → 4 - 10 + k = 0 → k = 6。这是利用方程根的定义求解。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (29, '在直角三角形ABC中，∠C=90°，AC=3，BC=4，则斜边AB上的高为 ___。✨', 'FILL_BLANK', 'MEDIUM', 7.00, 1, '数学', null, '["12/5", "2.4"]', '[{"point": "正确求出斜边长", "score": 2}, {"point": "利用面积相等建立方程", "score": 3}, {"point": "得出正确答案", "score": 2}]', '斜边AB=5（勾股定理）。利用面积相等：AC×BC/2 = AB×h/2 → 12/2 = 5h/2 → h=12/5=2.4。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (30, '从数字1,2,3,4,5中任取3个组成无重复三位数，该数是偶数的概率为 ___。🎲', 'FILL_BLANK', 'MEDIUM', 8.00, 1, '数学', null, '["2/5"]', '[{"point": "正确计算总情况数", "score": 2}, {"point": "正确计算偶数情况数", "score": 4}, {"point": "正确化简概率", "score": 2}]', '总情况数：5×4×3=60种。偶数要求个位为2或4，各有4×3=12种，共24种。概率=24/60=2/5。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (31, '已知函数f(x)=2^x，且f(a)=8，则a = ___。🤔', 'FILL_BLANK', 'MEDIUM', 6.00, 1, '数学', null, '["3"]', '[{"point": "建立方程2^a=8", "score": 2}, {"point": "将8化为2的幂", "score": 2}, {"point": "正确求解a", "score": 2}]', '2^a = 8 = 2³，根据指数函数单调性可得a=3。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (32, '等差数列{aₙ}的前5项和为30，且a₅=10，则首项a₁ = ___。📝', 'FILL_BLANK', 'MEDIUM', 7.00, 1, '数学', null, '["2"]', '[{"point": "正确使用求和公式", "score": 3}, {"point": "正确代入已知量", "score": 2}, {"point": "准确求解", "score": 2}]', 'S₅ = (a₁ + a₅)×5/2 = 30 → (a₁ + 10)×2.5 = 30 → a₁ + 10 = 12 → a₁ = 2。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (33, 'sin(π/6) + cos(π/3) = ___。🎯', 'FILL_BLANK', 'MEDIUM', 5.00, 1, '数学', null, '["1"]', '[{"point": "正确回忆特殊角三角函数值", "score": 3}, {"point": "准确计算结果", "score": 2}]', 'sin(π/6)=1/2，cos(π/3)=1/2，两者之和为1。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (34, '函数y = x³的导数y\' = ___。💡', 'FILL_BLANK', 'MEDIUM', 5.00, 1, '数学', null, '["3x²"]', '[{"point": "应用幂函数求导法则", "score": 3}, {"point": "结果正确", "score": 2}]', '根据幂函数求导法则，(x^n)\' = nx^(n-1)，所以(x³)\' = 3x²。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (35, '不等式2x - 5 > 3x + 2的解为x ___ -7。🧮', 'FILL_BLANK', 'MEDIUM', 6.00, 1, '数学', null, '["<"]', '[{"point": "正确移项合并", "score": 3}, {"point": "正确处理不等号方向", "score": 3}]', '移项得：2x - 3x > 2 + 5 → -x > 7 → x < -7（注意不等号方向变化）。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (36, '计算：log₂8 + log₃9 = ___。🌟', 'FILL_BLANK', 'MEDIUM', 6.00, 1, '数学', null, '["5"]', '[{"point": "正确拆分对数", "score": 3}, {"point": "准确计算结果", "score": 3}]', 'log₂8 = log₂(2³) = 3，log₃9 = log₃(3²) = 2，所以和为5。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (37, '已知向量a = (2,3)，向量b = (1,-2)，则a·b = ___。📐', 'FILL_BLANK', 'MEDIUM', 6.00, 1, '数学', null, '["-4"]', '[{"point": "正确应用点积公式", "score": 3}, {"point": "准确计算", "score": 3}]', '点积a·b = 2×1 + 3×(-2) = 2 - 6 = -4。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (38, '📐 某游乐园的摩天轮半径为50米，其中心距地面60米。小明从最低点登上摩天轮，摩天轮匀速旋转，每12分钟转一圈。请建立函数模型描述小明距离地面的高度与时间的关系，并计算他在5分钟时距离地面的高度（精确到0.1米）。请详细说明你的建模过程和解题思路～', 'ESSAY', 'MEDIUM', 10.00, 1, '数学', null, '""', '[{"point": "正确建立三角函数模型（确定周期、振幅、相位和垂直位移）", "score": 4}, {"point": "给出正确的函数表达式", "score": 2}, {"point": "正确代入t=5进行计算并得出精确结果", "score": 2}, {"point": "解题思路清晰，表达完整，有适当的图示或说明", "score": 2}]', '本题应采用三角函数模型h(t)=60+50sin(πt/6-π/2)或h(t)=60-50cos(πt/6)，其中t为时间（分钟）。当t=5时，h(5)=60+50sin(5π/6-π/2)=60+50sin(π/3)=60+50×(√3/2)≈60+43.3=103.3米。需要建立坐标系，确定振幅、周期、相位和垂直位移四个参数。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (39, '🎯 某商场举办抽奖活动，有A、B两个箱子。A箱有3个红球和2个白球，B箱有4个红球和6个白球。参与者先从A箱随机取出一球放入B箱，然后从B箱随机取出一球。若最终取出的是红球则中奖。请计算中奖概率，并解释全概率公式的应用过程。请画出概率树图辅助说明哦！', 'ESSAY', 'MEDIUM', 10.00, 1, '数学', null, '""', '[{"point": "正确分析两种情况并画出概率树图", "score": 3}, {"point": "正确计算每种情况的条件概率", "score": 3}, {"point": "正确应用全概率公式得出最终结果", "score": 2}, {"point": "清晰解释全概率公式的应用思路和意义", "score": 2}]', '使用全概率公式，分两种情况讨论：从A箱取出红球（概率3/5），此时B箱变为5红6白，从B箱抽红球概率5/11；从A箱取出白球（概率2/5），此时B箱变为4红7白，抽红球概率4/11。总概率=(3/5)×(5/11)+(2/5)×(4/11)=15/55+8/55=23/55≈41.8%。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (40, '🔍 已知等差数列{aₙ}的前n项和为Sₙ，且S₅=35，S₁₀=120。请在答题纸上详细推导求出该数列的通项公式aₙ和前n项和公式Sₙ，并计算S₂₀的值。请展示完整的代数推导过程，不要跳步哦～', 'ESSAY', 'MEDIUM', 10.00, 1, '数学', null, '""', '[{"point": "正确设立未知数并列出方程组", "score": 3}, {"point": "正确求解方程组得到首项和公差", "score": 3}, {"point": "正确写出通项公式aₙ和前n项和公式Sₙ", "score": 2}, {"point": "正确计算S₂₀并展示完整推导过程", "score": 2}]', '设等差数列首项为a₁，公差为d。根据Sₙ=n/2[2a₁+(n-1)d]，得方程组：5/2[2a₁+4d]=35→a₁+2d=7；10/2[2a₁+9d]=120→2a₁+9d=24。解得a₁=3，d=2。因此aₙ=3+2(n-1)=2n+1，Sₙ=n/2[2×3+(n-1)×2]=n(n+2)。S₂₀=20×22=440。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (41, '📊 某品牌手机电池的使用寿命（单位：小时）服从正态分布N(μ,σ²)。随机抽取36部手机测试，测得样本均值x̄=1200小时，样本标准差s=100小时。请在显著性水平α=0.05下，构造μ的置信区间，并解释置信区间的统计意义。请说明为什么使用t分布而不是z分布～', 'ESSAY', 'MEDIUM', 10.00, 1, '数学', null, '""', '[{"point": "正确判断使用t分布并说明理由", "score": 3}, {"point": "正确计算标准误和查找出临界值t", "score": 3}, {"point": "正确构造并计算出置信区间", "score": 2}, {"point": "准确解释置信区间的统计意义", "score": 2}]', '由于总体方差未知且样本量n=36<40，应使用t分布。自由度df=35，α=0.05时双侧临界值t≈2.03。置信区间为x̄±t×(s/√n)=1200±2.03×(100/6)=1200±33.83，即(1166.17,1233.83)。统计意义：我们有95%的置信度认为总体均值μ在此区间内。t分布用于小样本且总体方差未知的情况。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (42, '🌐 在平面直角坐标系中，已知圆C的方程为x²+y²-4x+6y-12=0。请通过配方法求出圆心坐标和半径，并求过点P(5,2)且与圆C相切的直线方程。请写出所有可能的切线方程，并说明分类讨论的依据。加油哦！', 'ESSAY', 'MEDIUM', 10.00, 1, '数学', null, '""', '[{"point": "正确通过配方求出圆心和半径", "score": 2}, {"point": "正确判断点P与圆的位置关系", "score": 2}, {"point": "分类讨论斜率存在和不存在两种情况", "score": 3}, {"point": "正确求出所有切线方程并验证", "score": 3}]', '配方得(x²-4x+4)+(y²+6y+9)=12+4+9→(x-2)²+(y+3)²=25，圆心C(2,-3)，半径r=5。点P(5,2)在圆外。分两种情况：1)斜率k存在，设切线y-2=k(x-5)，利用圆心到直线距离等于半径|k×2-(-3)+2-5k|/√(k²+1)=5，解得k=4/3，得切线4x-3y-14=0。2)斜率不存在，x=5也满足。因此有两条切线。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (43, '📈 设函数f(x)=x³-3x²-9x+5，请详细分析该函数的单调性、极值点、拐点，并绘制函数图像的大致形状。请说明你的分析步骤，包括求导、解方程、列表格等方法。思考要严谨哦！', 'ESSAY', 'MEDIUM', 10.00, 1, '数学', null, '""', '[{"point": "正确求出一阶和二阶导数", "score": 2}, {"point": "正确分析单调区间和极值点", "score": 3}, {"point": "正确求出拐点并分析凹凸性", "score": 2}, {"point": "综合信息绘制图像并说明关键特征", "score": 3}]', 'f\'(x)=3x²-6x-9=3(x+1)(x-3)，令f\'(x)=0得x=-1,3。f\'\'(x)=6x-6，令f\'\'(x)=0得x=1。单调性：x<-1时f\'>0，f递增；-1<x<3时f\'<0，f递减；x>3时f\'>0，f递增。极值：f(-1)=10为极大值，f(3)=-22为极小值。拐点：(1,-6)。根据以上信息可绘制图像。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (44, '🏗️ 某工厂要建造一个容积为108立方米的无盖长方体水池，底面为正方形。若底面造价为100元/平方米，侧面造价为50元/平方米，请建立总造价函数，并求出使总造价最低的水池尺寸。请用均值不等式或导数法求解，并验证你的结果确实是最小值～', 'ESSAY', 'MEDIUM', 10.00, 1, '数学', null, '""', '[{"point": "正确设立变量并建立总造价函数", "score": 3}, {"point": "正确化简函数并选择合适的优化方法", "score": 3}, {"point": "正确求解并得出具体尺寸", "score": 2}, {"point": "验证结果确实为最小值", "score": 2}]', '设底面边长为x米，高为h米。容积x²h=108→h=108/x²。总造价y=100x²+4×x×h×50=100x²+200x×(108/x²)=100x²+21600/x。求导得y\'=200x-21600/x²，令y\'=0→200x³=21600→x³=108→x=3×∛4≈4.76米。h=108/x²≈4.76米。用均值不等式也可证明当x=2h时取最小值，即x=∛(108×2)≈4.76米。验证二阶导数为正，确为最小值。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (45, '🔢 解不等式：(x²-4x+3)/(x²-9) ≥ 0。请详细说明解题步骤，包括：1)因式分解；2)找出临界点；3)用数轴法分析符号变化；4)考虑分母不为零的限制条件；5)写出最终解集。要细心哦，分式不等式容易有陷阱～', 'ESSAY', 'MEDIUM', 10.00, 1, '数学', null, '""', '[{"point": "正确因式分解并找出所有临界点", "score": 2}, {"point": "正确识别分母限制条件（x≠3）", "score": 2}, {"point": "用数轴法正确分析各区间符号", "score": 3}, {"point": "正确写出最终解集（注意端点取舍）", "score": 3}]', '因式分解得(x-1)(x-3)/[(x-3)(x+3)]≥0。临界点为x=-3,1,3（x=3时分母为零，舍去）。分三个区间讨论：x<-3时，分子正负负得正>0，满足； -3<x<1时，负正负负得负，不满足；1<x<3时，正正负得负，不满足；x>3时，正正正得正>0，满足。x=1取等号，x=3不取。最终解集：(-∞,-3)∪[1,3)∪(3,+∞)。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (46, '🎓 在△ABC中，已知∠A=60°, b=5, c=8。请用余弦定理求边a的长度，再用正弦定理求∠B和∠C的大小（保留到度）。最后计算三角形的面积。请展示完整的公式推导和计算过程，并说明在什么情况下三角形有两解、一解或无解～', 'ESSAY', 'MEDIUM', 10.00, 1, '数学', null, '""', '[{"point": "正确应用余弦定理求出边a", "score": 2}, {"point": "正确应用正弦定理求∠B并判断舍取", "score": 3}, {"point": "正确求出∠C和三角形面积", "score": 2}, {"point": "清晰讨论SSA情况下解的个数判定条件", "score": 3}]', '余弦定理：a²=b²+c²-2bccosA=25+64-2×5×8×0.5=49→a=7。正弦定理：a/sinA=b/sinB→7/(√3/2)=5/sinB→sinB=5√3/14≈0.6186→∠B≈38°。则∠C≈180-60-38=82°。面积S=½bcsinA=½×5×8×√3/2=10√3≈17.3。SSA情况下，当bsinA<a<b时有两解；a≥b时唯一解；a<bsinA时无解。', 0);
INSERT INTO exam_system.questions (id, content, type, difficulty, score, teacher_id, subject, options, correct_answer, scoring_criteria, explanation, deleted) VALUES (47, '💡 证明题：证明√2是无理数。请使用反证法，假设√2是有理数，即√2=p/q（p,q为互质正整数），然后通过代数变形和数论知识推导出矛盾。请详细写出每一步的推理过程，并解释为什么p,q必须都是偶数以及这与\'互质\'假设矛盾。这是经典的数学证明题，要严谨哦～', 'ESSAY', 'MEDIUM', 10.00, 1, '数学', null, '""', '[{"point": "正确设立反证法假设（√2=p/q，p,q互质）", "score": 2}, {"point": "正确推导出p²=2q²并证明p为偶数", "score": 3}, {"point": "正确推导出q也为偶数", "score": 3}, {"point": "明确指出矛盾并得出结论，逻辑严密", "score": 2}]', '反证法：假设√2=p/q（p,q互质，q≠0）。平方得2=p²/q²→p²=2q²，故p²为偶数，p必为偶数（奇数平方为奇数）。设p=2k，则(2k)²=2q²→4k²=2q²→q²=2k²，故q²为偶数，q必为偶数。则p,q均为偶数，有公因数2，与\'互质\'矛盾。故假设不成立，√2是无理数。', 0);
